338→    public static @NonNull ReaderTag getDefaultTagFromDbOrCreateInMemory(
339→            @NonNull Context context,
340→            TagUpdateClientUtilsProvider clientUtilsProvider
341→    ) {
342→        // getDefaultTag() tries to get the default tag from reader db by tag endpoint or tag name.
343→        // In case it cannot get the default tag from db, it creates it in memory with createTagFromTagName
344→        ReaderTag tag = getDefaultTag();
345→
346→        if (tag.isDefaultInMemoryTag()) {
347→            // if the tag was created in memory from createTagFromTagName
348→            // we need to set some fields as below before to use it
349→            tag.setTagTitle(context.getString(R.string.reader_following_display_name));
350→            tag.setTagDisplayName(context.getString(R.string.reader_following_display_name));
351→
352→            String baseUrl = clientUtilsProvider.getTagUpdateEndpointURL();
353→
354→            if (baseUrl.endsWith("/")) {
355→                baseUrl = baseUrl.substring(0, baseUrl.length() - 1);
356→            }
357→
358→            tag.setEndpoint(baseUrl + ReaderTag.FOLLOWING_PATH);
359→        }
360→
361→        return tag;
362→    }
