833→            }
834→
835→
836→            // if blog/feed is no longer followed, remove its posts tagged with "Followed Sites" or "P2"
837→            if (!isFollowed) {
838→                if (blogId != 0) {
839→                    db.delete("tbl_posts", "blog_id=? AND (tag_name=? OR tag_name=?)",
840→                            new String[]{Long.toString(blogId), ReaderTag.TAG_TITLE_FOLLOWED_SITES,
841→                                    ReaderTag.TAG_SLUG_P2});
842→                } else {
843→                    db.delete("tbl_posts", "feed_id=? AND (tag_name=? OR tag_name=?)",
844→                            new String[]{Long.toString(feedId), ReaderTag.TAG_TITLE_FOLLOWED_SITES,
845→                                    ReaderTag.TAG_SLUG_P2});
