2257→    @SuppressWarnings("unused")
2258→    @Subscribe(threadMode = ThreadMode.MAIN)
2259→    public void onEventMainThread(ReaderEvents.UpdatePostsStarted event) {
2260→        if (!isAdded()) {
2261→            return;
2262→        }
2263→        // check if the event is related to this instance of the ReaderPostListFragment
2264→        if (event.getReaderTag() != null && !isCurrentTag(event.getReaderTag())) {
2265→            return;
2266→        }
2267→        setIsUpdating(true, event.getAction());
2268→        setEmptyTitleDescriptionAndButton(false);
2269→        if (isPostAdapterEmpty()) showEmptyView();
2270→    }
