2272→    @SuppressWarnings("unused")
2273→    @Subscribe(threadMode = ThreadMode.MAIN)
2274→    public void onEventMainThread(ReaderEvents.UpdatePostsEnded event) {
2275→        if (!isAdded()) {
2276→            return;
2277→        }
2278→        // check if the event is related to this instance of the ReaderPostListFragment
2279→        if (event.getReaderTag() != null && !isCurrentTag(event.getReaderTag())) {
2280→            return;
2281→        }
2282→        setIsUpdating(false, event.getAction());
2283→        mHasUpdatedPosts = true;
2284→
2285→        // don't show new posts if user is searching - posts will automatically
2286→        // appear when search is exited
2287→        if (isSearchViewExpanded() || isSearching()) {
2288→            return;
2289→        }
2290→
2291→        // determine whether to show the "new posts" bar - when this is shown, the newly
2292→        // downloaded posts aren't displayed until the user taps the bar - only appears
2293→        // when there are new posts in a followed tag and the user has scrolled the list
2294→        // beyond the first post
2295→        if (event.getResult() == ReaderActions.UpdateResult.HAS_NEW
2296→            && event.getAction() == UpdateAction.REQUEST_NEWER
2297→            && getPostListType() == ReaderPostListType.TAG_FOLLOWED
2298→            && !isPostAdapterEmpty()
2299→            && (!isAdded() || !mRecyclerView.isFirstItemVisible())) {
2300→            showNewPostsBar();
2301→        } else if (event.getResult().isNewOrChanged()
2302→                   || event.getAction() == UpdateAction.REQUEST_REFRESH) {
2303→            refreshPosts();
2304→        } else {
2305→            boolean requestFailed = (event.getResult() == ReaderActions.UpdateResult.FAILED);
2306→            setEmptyTitleDescriptionAndButton(requestFailed);
2307→            // if we requested posts in order to fill a gap but the request failed or didn't
2308→            // return any posts, reload the adapter so the gap marker is reset (hiding its
2309→            // progress bar)
2310→            if (event.getAction() == UpdateAction.REQUEST_OLDER_THAN_GAP) {
2311→                reloadPosts();
2312→            }
2313→        }
2314→    }
