import org.wordpress.android.models.ReaderTag
import org.wordpress.android.models.ReaderTagType
import org.wordpress.android.ui.reader.utils.ReaderUtilsWrapper
import java.util.Locale
import javax.inject.Inject

class BloggingPromptsPostTagProvider @Inject constructor(
    private val readerUtilsWrapper: ReaderUtilsWrapper,
) {
    fun promptIdTag(
        tagUrl: String
    ): String = readerUtilsWrapper.getTagFromTagUrl(tagUrl)
        .takeIf { it.isNotBlank() }
        ?: BLOGGING_PROMPT_TAG

    fun promptIdSearchReaderTag(
        tagUrl: String
    ): ReaderTag = readerUtilsWrapper.getTagFromTagName(
        promptIdTag(tagUrl),
        ReaderTagType.FOLLOWED,
    ).ensureTagEndpoint()

    private fun ReaderTag.ensureTagEndpoint(): ReaderTag {
        if (!isTagTopic() && tagSlug.isNotBlank()) {
            endpoint = buildTagEndpoint(tagSlug)
        }
        return this
    }

    private fun buildTagEndpoint(tagSlug: String) =
        TAG_ENDPOINT_PREFIX + tagSlug.lowercase(Locale.ROOT) + TAG_ENDPOINT_SUFFIX

    companion object {
        const val BLOGGING_PROMPT_TAG = "dailyprompt"
        const val BLOGANUARY_TAG = "bloganuary"
        private const val TAG_ENDPOINT_PREFIX = "read/tags/"
        private const val TAG_ENDPOINT_SUFFIX = "/posts"
    }
}
